#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0; getchar(); // consume newline after T
    while(T--){
        char line[10005];
        if(!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        // split into words
        char *words[10000];
        int cnt = 0;
        char *p = line;
        while(*p){
            while(*p && isspace((unsigned char)*p)) p++; // skip spaces
            if(!*p) break;
            words[cnt++] = p; // start of a word
            while(*p && !isspace((unsigned char)*p)) p++; // move to end of word
            if(*p){ *p = '\0'; p++; }
        }
        // output in reverse order
        for(int i = cnt-1; i >= 0; --i){
            printf("%s", words[i]);
            if(i) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

