#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; string line; getline(cin, line); // consume endline after T
    while(T--){
        getline(cin, line);
        vector<string> words;
        for(size_t i=0;i<line.size();){
            while(i<line.size() && line[i]==' ') i++; // skip spaces
            if(i>=line.size()) break;
            size_t j=i;
            while(j<line.size() && line[j]!=' ') j++;
            words.emplace_back(line.substr(i, j-i));
            i=j;
        }
        for(int i=(int)words.size()-1;i>=0;--i){
            cout<<words[i];
            if(i) cout<<' ';
        }
        cout<<'\n';
    }
    return 0;
}

